"""
MABE Bootstrap: Optical Module 11 — Inverse Design Wrapper

Run: python3 bootstrap_optical_m11.py

Prereqs: optical/ modules M1-M9 must already be in the repo
         (applied from 0001_optical_module.patch)
         pip install miepython scipy

Creates:
  optical/inverse_design.py                — M11 inverse design optimizer
  tests/test_optical/test_inverse_design.py — 14 tests

API:
  inverse_design_photonic_glass(target_x, target_y, ...) → DesignResult
    scipy.optimize.differential_evolution over M6 photonic glass forward model
    Optimizes: diameter, packing fraction, absorber fraction
    Supports: material selection, underlayer coupling, diameter/phi bounds

  inverse_design_multilayer(target_centre_nm, ...) → DesignResult
    Optimizes H/L layer thicknesses for Bragg mirror stopband placement

  scan_materials(target_x, target_y) → ranked list across material combos

Validation:
  Green target (x=0.27, y=0.40): exact match (ΔE < 1)
  Blue target: converges with ΔE < 20
  Red target: correctly identifies difficulty (higher ΔE)
  TMM: 550nm stopband → ±5nm accuracy

Total with M1-M9: 40 optical tests passing
"""
import base64, pathlib

FILES = {
    "optical/inverse_design.py": "",
    "tests/test_optical/test_inverse_design.py": "",
}

def main():
    for path, b64 in FILES.items():
        p = pathlib.Path(path)
        p.parent.mkdir(parents=True, exist_ok=True)
        p.write_bytes(base64.b64decode(b64))
        print(f"  Wrote {path} ({len(base64.b64decode(b64)):,} bytes)")
    print()
    print("  python3 -m pytest tests/test_optical/ -v")
    print("  python3 optical/inverse_design.py  # self-test")

if __name__ == "__main__":
    main()